const https = require('https');

const domains = [
  'api.aviontechs.com',
  'app.aviontechs.com',
  'n8n.aviontechs.com',
  'grafana.aviontechs.com',
  'status.aviontechs.com'
];

const results = [];

for (const domain of domains) {
  try {
    const cert = await new Promise((resolve, reject) => {
      const req = https.get({ hostname: domain, port: 443, method: 'HEAD', rejectUnauthorized: false }, (res) => {
        const cert = res.socket.getPeerCertificate();
        resolve(cert);
      });
      req.on('error', reject);
      req.setTimeout(5000, () => { req.destroy(); reject(new Error('timeout')); });
    });
    const validTo = new Date(cert.valid_to);
    const daysLeft = Math.floor((validTo - Date.now()) / 86400000);
    results.push({ domain, daysLeft, validTo: validTo.toISOString().split('T')[0], ok: daysLeft > 14 });
  } catch (e) {
    results.push({ domain, daysLeft: -1, validTo: 'ERROR', ok: false, error: e.message });
  }
}

return [{ json: { sslCerts: results } }];

const health = $('Fetch System Health').item.json;
const monitoring = $('Fetch Monitoring Status').item.json;
const errors = $('Fetch Error Summary').item.json;
const ssl = $('Check SSL Certs').item.json;

// --- Severity tracking ---
let severity = 'ok'; // ok → warning → critical
function escalate(level) {
  if (level === 'critical') severity = 'critical';
  else if (level === 'warning' && severity !== 'critical') severity = 'warning';
}

// --- 1. System Health ---
const healthLines = [];
const subsystems = health.subsystems || health.services || {};
for (const [name, info] of Object.entries(subsystems)) {
  const status = typeof info === 'object' ? (info.status || info.state || 'unknown') : info;
  const icon = status === 'ok' || status === 'healthy' || status === 'connected' ? '✅' : status === 'degraded' ? '⚠️' : '❌';
  healthLines.push(`${icon} ${name}: ${status}`);
  if (icon === '❌') escalate('critical');
  else if (icon === '⚠️') escalate('warning');
}
if (healthLines.length === 0) healthLines.push(health.status === 'ok' ? '✅ All systems operational' : '⚠️ Status: ' + (health.status || 'unknown'));

// --- 2. VPS Resources ---
const vps = monitoring.vps || monitoring.server || {};
const vpsLines = [];
if (vps.cpu !== undefined) vpsLines.push(`CPU: ${vps.cpu}%`);
if (vps.memory !== undefined) vpsLines.push(`Memory: ${vps.memory}%`);
if (vps.disk !== undefined) vpsLines.push(`Disk: ${vps.disk}%`);
if (vps.uptime) vpsLines.push(`Uptime: ${vps.uptime}`);
if (vpsLines.length === 0) vpsLines.push('No VPS metrics available');
if (vps.cpu > 90 || vps.memory > 90 || vps.disk > 90) escalate('critical');
else if (vps.cpu > 75 || vps.memory > 75 || vps.disk > 85) escalate('warning');

// --- 3. SSL Certs ---
const sslCerts = ssl.sslCerts || [];
const sslLines = sslCerts.map(c => {
  const icon = c.error ? '❌' : c.daysLeft > 14 ? '✅' : c.daysLeft > 7 ? '⚠️' : '❌';
  if (icon === '❌') escalate('critical');
  else if (icon === '⚠️') escalate('warning');
  return `${icon} ${c.domain}: ${c.error ? c.error : c.daysLeft + 'd left (expires ' + c.validTo + ')'}`;
});
if (sslLines.length === 0) sslLines.push('No SSL data');

// --- 4. Backups ---
const backups = monitoring.backups || monitoring.backup || {};
const backupLines = [];
if (backups.lastRun) backupLines.push(`Last: ${backups.lastRun}`);
if (backups.status) backupLines.push(`Status: ${backups.status}`);
if (backups.size) backupLines.push(`Size: ${backups.size}`);
if (backupLines.length === 0) backupLines.push('No backup info available');
if (backups.status === 'failed') escalate('critical');

// --- 5. Errors (24h) ---
const errorList = errors.errors || errors.summary || [];
const totalErrors = errors.totalErrors || errors.total || errorList.length || 0;
const errorLines = [];
if (totalErrors > 0) {
  errorLines.push(`**${totalErrors}** errors in last 24h`);
  const topErrors = (Array.isArray(errorList) ? errorList : []).slice(0, 5);
  topErrors.forEach(e => {
    errorLines.push(`  • ${e.message || e.error || e.name || 'Unknown'} (×${e.count || 1})`);
  });
  if (totalErrors > 10) escalate('warning');
  if (totalErrors > 50) escalate('critical');
} else {
  errorLines.push('No errors in last 24h');
}

// --- 6. Active Alerts / Open PRs ---
const alerts = monitoring.alerts || [];
const prs = monitoring.pullRequests || monitoring.prs || [];
const alertLines = [];
if (alerts.length > 0) {
  alerts.forEach(a => alertLines.push(`🔔 ${a.name || a.alertname || a.title}: ${a.status || a.state || 'firing'}`));
  escalate('warning');
} else {
  alertLines.push('No active alerts');
}
if (prs.length > 0) {
  prs.forEach(pr => alertLines.push(`📝 PR #${pr.number || '?'}: ${pr.title || 'Untitled'}`));
}

// --- Color ---
const colors = { ok: 3066993, warning: 16776960, critical: 15548997 }; // green, yellow, red

// --- Build Discord embed ---
const embed = {
  title: '🏥 Daily System Health Rollup',
  color: colors[severity],
  timestamp: new Date().toISOString(),
  fields: [
    { name: '🖥️ System Health', value: healthLines.join('\n'), inline: false },
    { name: '📊 VPS Resources', value: vpsLines.join('\n'), inline: true },
    { name: '🔒 SSL Certificates', value: sslLines.join('\n'), inline: false },
    { name: '💾 Backups', value: backupLines.join('\n'), inline: true },
    { name: '🐛 Errors (24h)', value: errorLines.join('\n'), inline: false },
    { name: '🔔 Alerts & PRs', value: alertLines.join('\n'), inline: false },
  ],
  footer: { text: `Severity: ${severity.toUpperCase()}` },
};

return [{ json: { embed, severity } }];
